#include "dosrecomp/runtime/real_mode_memory.hpp"
#include <cstdlib>
int main() { dosrecomp::runtime::real_mode_memory memory; const auto write = memory.write8(0x10ffef, 0xaa); const auto read = memory.read8(0x10ffef); const auto logical_write = memory.write8(0x1234, 0x5678, 0x55); const auto logical_read = memory.read8(0x1234, 0x5678); const auto word = memory.write16(2, 0x1234); const auto word_read = memory.read16(2); const auto logical_word = memory.write16(0x100, 0x20, 0xabcd); const auto logical_word_read = memory.read16(0x100, 0x20); return write && read && *read == 0xaa && logical_write && logical_read && *logical_read == 0x55 && word && word_read && *word_read == 0x1234 && logical_word && logical_word_read && *logical_word_read == 0xabcd && !memory.read8(0x110000) && !memory.read16(0x10ffff) ? EXIT_SUCCESS : EXIT_FAILURE; }
